import type {
    PatchScrumboardBody,
    ProjectBoardColumn,
    ScrumboardLaneId,
    ScrumboardLaneMove,
} from '@motivation/shared';
import stylesText from './project-scrumboard.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { formatProjectStatusLabel, projectStatusClass } from '../project-shared.js';
import { ProjectsService } from '../../../../services/projects.service.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';

const LANE_OPTIONS: Array<{ id: ScrumboardLaneId; label: string }> = [
    { id: 'active-sprint', label: 'Active Sprint' },
    { id: 'completed', label: 'Completed' },
    { id: 'high-priority', label: 'High Priority' },
    { id: 'medium-priority', label: 'Medium Priority' },
    { id: 'low-priority', label: 'Low Priority' },
    { id: 'superseded', label: 'Superseded' },
];

const template = document.createElement('template');
template.innerHTML = `
<div class="state" id="loading">Loading scrumboard…</div>
<div class="state" id="error" hidden></div>
<div class="sprint-header" hidden id="sprint-header">
    <label class="sprint-field">
        <span class="sprint-label">Sprint</span>
        <input type="text" id="sprint-name" maxlength="80" />
    </label>
    <label class="sprint-field">
        <span class="sprint-label">Goal</span>
        <input type="text" id="sprint-goal" maxlength="200" />
    </label>
    <button type="button" id="save-sprint">Save</button>
    <span class="sprint-feedback" id="sprint-feedback" hidden></span>
</div>
<div class="pending-moves" hidden id="pending-moves">
    <span id="pending-count"></span>
    <button type="button" id="apply-moves">Apply moves</button>
    <button type="button" id="cancel-moves">Cancel</button>
</div>
<pre class="board-error" id="board-error" hidden></pre>
<div class="board-columns" id="columns" hidden></div>
<template id="column-template">
    <details class="board-column">
        <summary class="column-summary">
            <span class="column-title"></span>
            <span class="column-hint">Tap for stories</span>
        </summary>
        <ul class="board-list"></ul>
    </details>
</template>
<template id="item-template">
    <li class="board-entry">
        <details class="board-item">
            <summary class="item-summary">
                <span class="item-text">
                    <span class="item-id"></span>
                    <span class="item-title"></span>
                </span>
                <span class="status"></span>
            </summary>
            <p class="item-meta"></p>
            <label class="move-field">
                <span>Move to</span>
                <select class="move-select"></select>
            </label>
        </details>
    </li>
</template>
`;

export class ProjectScrumboard extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private boardErrorEl!: HTMLElement;
    private columnsEl!: HTMLElement;
    private sprintHeaderEl!: HTMLElement;
    private sprintNameInput!: HTMLInputElement;
    private sprintGoalInput!: HTMLInputElement;
    private saveSprintButton!: HTMLButtonElement;
    private sprintFeedbackEl!: HTMLElement;
    private pendingMovesEl!: HTMLElement;
    private pendingCountEl!: HTMLElement;
    private applyMovesButton!: HTMLButtonElement;
    private cancelMovesButton!: HTMLButtonElement;
    private columnTemplateEl!: HTMLTemplateElement;
    private itemTemplateEl!: HTMLTemplateElement;
    private loadSequence = 0;
    private pendingMoves: ScrumboardLaneMove[] = [];
    private readonly log = createComponentLogger('project-scrumboard');

    static get observedAttributes(): string[] {
        return ['project-id'];
    }

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.boardErrorEl = this.shadowRootRef.getElementById('board-error') as HTMLElement;
        this.columnsEl = this.shadowRootRef.getElementById('columns') as HTMLElement;
        this.sprintHeaderEl = this.shadowRootRef.getElementById('sprint-header') as HTMLElement;
        this.sprintNameInput = this.shadowRootRef.getElementById('sprint-name') as HTMLInputElement;
        this.sprintGoalInput = this.shadowRootRef.getElementById('sprint-goal') as HTMLInputElement;
        this.saveSprintButton = this.shadowRootRef.getElementById('save-sprint') as HTMLButtonElement;
        this.sprintFeedbackEl = this.shadowRootRef.getElementById('sprint-feedback') as HTMLElement;
        this.pendingMovesEl = this.shadowRootRef.getElementById('pending-moves') as HTMLElement;
        this.pendingCountEl = this.shadowRootRef.getElementById('pending-count') as HTMLElement;
        this.applyMovesButton = this.shadowRootRef.getElementById('apply-moves') as HTMLButtonElement;
        this.cancelMovesButton = this.shadowRootRef.getElementById('cancel-moves') as HTMLButtonElement;
        this.columnTemplateEl = this.shadowRootRef.getElementById('column-template') as HTMLTemplateElement;
        this.itemTemplateEl = this.shadowRootRef.getElementById('item-template') as HTMLTemplateElement;

        this.saveSprintButton.addEventListener('click', () => void this.saveSprintMetadata());
        this.applyMovesButton.addEventListener('click', () => void this.applyPendingMoves());
        this.cancelMovesButton.addEventListener('click', () => this.clearPendingMoves());

        void this.loadData();
    }

    attributeChangedCallback(): void {
        if (!this.isConnected || !this.loadingEl) return;
        void this.loadData();
    }

    private async loadData(): Promise<void> {
        const projectId = this.getAttribute('project-id');
        if (projectId !== 'motivation' || !this.loadingEl) return;

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.boardErrorEl.hidden = true;
        this.columnsEl.hidden = true;
        this.sprintHeaderEl.hidden = true;

        try {
            const dashboard = await ProjectsService.fetchMotivationDashboard();
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.sprintNameInput.value = dashboard.scrumboard.sprintName ?? '';
            this.sprintGoalInput.value = dashboard.scrumboard.goal ?? '';
            this.renderColumns(dashboard.scrumboard.columns);
        } catch (error) {
            this.log.error('Failed to load scrumboard', error);
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = 'Failed to load scrumboard.';
        }
    }

    private renderColumns(columns: ProjectBoardColumn[]): void {
        this.columnsEl.replaceChildren(...columns.map((column) => this.buildColumn(column)));
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.sprintHeaderEl.hidden = false;
        this.columnsEl.hidden = false;
        this.refreshPendingPanel();
    }

    private buildColumn(column: ProjectBoardColumn): HTMLElement {
        const fragment = this.columnTemplateEl.content.cloneNode(true) as DocumentFragment;
        const columnEl = fragment.querySelector('.board-column') as HTMLElement;
        const title = fragment.querySelector('.column-title') as HTMLElement;
        const list = fragment.querySelector('.board-list') as HTMLElement;
        title.textContent = `${column.title} (${column.items.length})`;
        if (column.id === 'active-sprint' || column.id === 'high-priority') {
            (columnEl as HTMLDetailsElement).open = true;
        }

        if (column.items.length === 0) {
            const empty = document.createElement('li');
            empty.className = 'board-item board-item--empty';
            empty.textContent = 'No stories in this lane.';
            list.appendChild(empty);
            return columnEl;
        }

        for (const item of column.items) {
            const itemFragment = this.itemTemplateEl.content.cloneNode(true) as DocumentFragment;
            (itemFragment.querySelector('.item-id') as HTMLElement).textContent =
                item.points == null ? `Story ${item.id}` : `Story ${item.id} · ${item.points} pts`;

            const status = itemFragment.querySelector('.status') as HTMLElement;
            status.className = projectStatusClass(item.status);
            status.textContent = formatProjectStatusLabel(item.status);

            (itemFragment.querySelector('.item-title') as HTMLElement).textContent = item.title;
            (itemFragment.querySelector('.item-meta') as HTMLElement).textContent =
                item.points == null ? 'No estimate recorded for this item.' : `${item.points} story points`;

            const moveSelect = itemFragment.querySelector('.move-select') as HTMLSelectElement;
            const placeholder = document.createElement('option');
            placeholder.value = '';
            placeholder.textContent = '— keep —';
            moveSelect.appendChild(placeholder);
            for (const lane of LANE_OPTIONS) {
                if (lane.id === column.id) continue;
                const opt = document.createElement('option');
                opt.value = lane.id;
                opt.textContent = lane.label;
                moveSelect.appendChild(opt);
            }
            moveSelect.addEventListener('change', () => {
                if (moveSelect.value === '') return;
                this.queueMove({
                    id: item.id,
                    fromLane: column.id as ScrumboardLaneId,
                    toLane: moveSelect.value as ScrumboardLaneId,
                });
                moveSelect.value = '';
            });

            list.appendChild(itemFragment);
        }
        return columnEl;
    }

    private queueMove(move: ScrumboardLaneMove): void {
        this.pendingMoves.push(move);
        this.refreshPendingPanel();
    }

    private clearPendingMoves(): void {
        this.pendingMoves = [];
        this.refreshPendingPanel();
    }

    private refreshPendingPanel(): void {
        if (this.pendingMoves.length === 0) {
            this.pendingMovesEl.hidden = true;
            return;
        }
        this.pendingMovesEl.hidden = false;
        this.pendingCountEl.textContent = `${this.pendingMoves.length} pending move${this.pendingMoves.length === 1 ? '' : 's'}`;
    }

    private async applyPendingMoves(): Promise<void> {
        if (this.pendingMoves.length === 0) return;
        const body: PatchScrumboardBody = { moves: this.pendingMoves };
        this.applyMovesButton.disabled = true;
        this.boardErrorEl.hidden = true;
        try {
            await ProjectsService.patchScrumboard(body);
            this.pendingMoves = [];
            await this.loadData();
        } catch (error) {
            this.log.error('Failed to apply moves', error);
            this.boardErrorEl.hidden = false;
            this.boardErrorEl.textContent = (error instanceof Error ? error.stack ?? error.message : String(error));
        } finally {
            this.applyMovesButton.disabled = false;
            this.refreshPendingPanel();
        }
    }

    private async saveSprintMetadata(): Promise<void> {
        const body: PatchScrumboardBody = {
            sprintName: this.sprintNameInput.value.trim(),
            sprintGoal: this.sprintGoalInput.value.trim(),
        };
        this.saveSprintButton.disabled = true;
        this.boardErrorEl.hidden = true;
        try {
            await ProjectsService.patchScrumboard(body);
            this.sprintFeedbackEl.hidden = false;
            this.sprintFeedbackEl.textContent = 'Saved';
            setTimeout(() => { this.sprintFeedbackEl.hidden = true; }, 1500);
        } catch (error) {
            this.log.error('Failed to save sprint metadata', error);
            this.boardErrorEl.hidden = false;
            this.boardErrorEl.textContent = (error instanceof Error ? error.stack ?? error.message : String(error));
        } finally {
            this.saveSprintButton.disabled = false;
        }
    }
}

if (!customElements.get('project-scrumboard')) {
    customElements.define('project-scrumboard', ProjectScrumboard);
}
